private void waitIfAllChangelogsCompletelyRead() {
    tasksAndActionsLock.lock();
    try {
        while (allWorkDone() && fetchDeadlineClientInstanceId == -1L) {
            isIdle.set(true);
            tasksAndActionsCondition.await();
