private void maybePerformTransportMaintenance() {
    if (metricsConnector != null) {
        final long nowMs = time.milliseconds();
        if (nowMs - lastTransportMaintenanceMs >= TRANSPORT_MAINTENANCE_INTERVAL_MS) {
            lastTransportMaintenanceMs = nowMs;
