package org.apache.kafka.streams.state.internals;

import org.apache.kafka.common.header.internals.RecordHeaders;
import org.apache.kafka.common.metrics.Metrics;
import org.apache.kafka.common.utils.Bytes;
import org.apache.kafka.common.utils.LogContext;
import org.apache.kafka.streams.processor.internals.MockStreamsMetrics;

/**
 * Fray test to detect the deadlock between ThreadCache.resize() and
 * ThreadCache.put() when eviction triggers a flush listener callback
 * that re-enters ThreadCache.
 *
 * The deadlock occurs because resize() holds ThreadCache.this then
 * acquires a NamedCache lock, while the put() -> evict -> flush ->
 * listener callback path holds a NamedCache lock and then tries to
 * acquire ThreadCache.this (via getOrCreateCache).
 */
public class ThreadCacheDeadlockTest {

    public static void main(final String[] args) throws Exception {
        final LogContext logContext = new LogContext("test ");
        // Use a small cache so that puts trigger eviction quickly.
        final long cacheSize = 200L;
        final ThreadCache cache = new ThreadCache(logContext, cacheSize, new MockStreamsMetrics(new Metrics()));

        final String namespace1 = "0.0-store1";
        final String namespace2 = "0.0-store2";

        // Register a flush listener on namespace1 that, when eviction flushes
        // dirty entries, calls back into the ThreadCache by putting into namespace2.
        // This simulates the real scenario where CachingKeyValueStore's flush
        // listener forwards records downstream, causing another store to put
        // into the same ThreadCache.
        cache.addDirtyEntryFlushListener(namespace1, dirtyEntries -> {
            // This callback runs while holding the NamedCache lock for namespace1.
            // Putting into namespace2 will call getOrCreateCache() which needs
            // synchronized(ThreadCache.this). If resize() holds ThreadCache.this
            // and is waiting for the namespace1 NamedCache lock, we deadlock.
            for (final ThreadCache.DirtyEntry entry : dirtyEntries) {
                cache.put(
                    namespace2,
                    entry.key(),
                    new LRUCacheEntry(new byte[1], new RecordHeaders(), true, 0L, 0L, 0, "", new byte[0], new byte[0])
                );
            }
        });

        // We also need a listener for namespace2, otherwise eviction will fail.
        cache.addDirtyEntryFlushListener(namespace2, dirtyEntries -> { });

        // Pre-populate namespace1 so it has dirty entries that will be flushed on eviction.
        for (int i = 0; i < 3; i++) {
            cache.put(
                namespace1,
                Bytes.wrap(new byte[]{(byte) i}),
                new LRUCacheEntry(new byte[10], new RecordHeaders(), true, 0L, 0L, 0, "", new byte[0], new byte[0])
            );
        }

        // Thread 1: puts into namespace1, which may trigger eviction -> flush -> callback -> put into namespace2 -> getOrCreateCache -> synchronized(ThreadCache.this)
        // Lock order: NamedCache(namespace1) -> ThreadCache.this
        final Thread putter = new Thread(() -> {
            for (int i = 3; i < 10; i++) {
                cache.put(
                    namespace1,
                    Bytes.wrap(new byte[]{(byte) i}),
                    new LRUCacheEntry(new byte[10], new RecordHeaders(), true, 0L, 0L, 0, "", new byte[0], new byte[0])
                );
            }
        });

        // Thread 2: resize shrinks the cache, which does synchronized(ThreadCache.this) -> synchronized(NamedCache) -> evict
        // Lock order: ThreadCache.this -> NamedCache(namespace1)
        final Thread resizer = new Thread(() -> {
            cache.resize(100L);
        });

        putter.start();
        resizer.start();

        putter.join();
        resizer.join();
    }
}

